        "filePath": "/Users/michelkerkmeester/MEGA/Development/Code_Environment/Public/.opencode/specs/system-speckit/029-memory-search-intelligence/001-speckit-memory/025-off-corpus-eval-fixture-gate/spec.md",
        "title": "Feature Specification: Off-Corpus Eval Fixture and False-Confirm Gate [template:level_2/spec.md]",
        "isConstitutional": false,
